import{_ as i,c as e,o as a,ae as t}from"./chunks/framework.CnPnaHem.js";const r="/docs/assets/monolithic-architure.gmvC8aa2.png",c="/docs/assets/scale-monolithic.BZ4qNh4J.png",p=JSON.parse('{"title":"Kiến trúc Monolithic","description":"","frontmatter":{},"headers":[],"relativePath":"sidebars/technical-skill/1.-microservice-and-domain-driven-design.md","filePath":"sidebars/technical-skill/1.-microservice-and-domain-driven-design.md"}'),o={name:"sidebars/technical-skill/1.-microservice-and-domain-driven-design.md"};function l(h,n,s,d,g,m){return a(),e("div",null,n[0]||(n[0]=[t('<h1 id="kien-truc-monolithic" tabindex="-1">Kiến trúc Monolithic <a class="header-anchor" href="#kien-truc-monolithic" aria-label="Permalink to &quot;Kiến trúc Monolithic&quot;">​</a></h1><ul><li>Là kiến trúc phía Server của ứng dụng dạng Client-Server</li><li>Toàn bộ team làm việc trên một Project(Solution)</li><li>Được đóng gói thành một file hoặc một thư mục khi triển khai</li><li>Dễ dàng develop, deploy, scale với những dự án nhỏ</li></ul><img src="'+r+'" alt="DDD" style="border:10px solid #EEEEEE;border-radius:8px;"><h4 id="mo-rong-he-thong" tabindex="-1">Mở rộng hệ thống : <a class="header-anchor" href="#mo-rong-he-thong" aria-label="Permalink to &quot;Mở rộng hệ thống :&quot;">​</a></h4><ul><li>Vertical Scaling: chính là nâng cấp Ram, Cpu, SSD cho Server để có thể đáp ứng được khả năng mở rộng</li><li>Horizontal Scaling: Cái này thì sẽ phức tạp hơn , mở rộng về chiều ngang đòi hỏi phải cấu hình nhiều hơn: <ul><li>Tạo nhiều Instance của Server giống hệt bản gốc ( ví dụ tạo thêm 2 bản nữa )</li><li>Lúc này không chỉ có một Server để phục vụ cho <code>ứng dụng</code> =&gt; Vấn đề: Làm thế nào để phân loại request, cache, ... cho từng Instance của Server.</li><li>Resolve: Load Balance</li><li>Tạo thêm một(or N) Database nữa , phân loại database dựa trên database nào đọc( Cấu hình cao hơn) , database nào để ghi, sau một thời gian cần đồng bộ dữ liệu từ Database ghi vào Database đọc</li></ul></li></ul><img src="'+c+'" alt="DDD" style="border:10px solid #EEEEEE;border-radius:8px;"><h4 id="van-đe" tabindex="-1">=&gt; Vấn đề : <a class="header-anchor" href="#van-đe" aria-label="Permalink to &quot;=&gt; Vấn đề :&quot;">​</a></h4><ul><li>Chỉ phù với những dự án nhỏ, hoặc ngắn hạn =&gt; những dự án Outsource cần tiến độ nhanh.</li><li>Với những dự án lớn, nhiều người tham gia: <ul><li>IDE bị quá tải, chậm.</li><li>Khó mở rộng, phân chia đội ngũ.</li><li>Thường gắn gắn chặt với một nền tảng, công nghệ, kém linh hoạt.</li></ul></li></ul><h1 id="kien-truc-microservice" tabindex="-1">Kiến trúc Microservice <a class="header-anchor" href="#kien-truc-microservice" aria-label="Permalink to &quot;Kiến trúc Microservice&quot;">​</a></h1>',9)]))}const v=i(o,[["render",l]]);export{p as __pageData,v as default};
